 1	import { Button, Flex, FlexItem, Tab, Tabs, TabTitleText, Tooltip } from '@patternfly/react-core';
 2	import React, { CSSProperties } from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { useNetflowContext } from '../../model/netflow-context';
 5	import { TimeRange } from '../../utils/datetime';
 6	import { useTheme } from '../../utils/theme-hook';
 7	import { ViewId } from '../netflow-traffic';
 8	
 9	export interface TabsContainerProps {
10	  selectedViewId: ViewId;
11	  selectView: (v: ViewId) => void;
12	  showHistogram: boolean;
13	  setShowViewOptions: (v: boolean) => void;
14	  setShowHistogram: (v: boolean) => void;
15	  setHistogramRange: (v: TimeRange | undefined) => void;
16	  isShowViewOptions: boolean;
17	  style?: CSSProperties;
18	}
19	
20	export const TabsContainer: React.FC<TabsContainerProps> = props => {
21	  const { t } = useTranslation('plugin__netobserv-plugin');
22	  const isDarkTheme = useTheme();
23	  const { caps } = useNetflowContext();
24	  const isAllowLoki = caps.allowLoki;
25	
26	  return (
27	    <Flex className="netflow-traffic-tabs-container" style={props.style}>
28	      <FlexItem id="tabs-container" flex={{ default: 'flex_1' }}>
29	        <Tabs
30	          className={`netflow-traffic-tabs ${isDarkTheme ? 'dark' : 'light'}`}
31	          usePageInsets
32	          activeKey={props.selectedViewId}
33	          onSelect={(event, eventkey) => props.selectView(eventkey as ViewId)}
34	          role="region"
35	        >
36	          <Tab
37	            className="overviewTabButton"
38	            eventKey={'overview'}
39	            title={<TabTitleText>{t('Overview')}</TabTitleText>}
40	          />
41	          <Tab
42	            className="tableTabButton"
43	            eventKey={'table'}
44	            isAriaDisabled={!isAllowLoki} // required instead of 'disabled' when used with a tooltip
45	            tooltip={
46	              !isAllowLoki ? (
47	                <Tooltip content={t('Only available when FlowCollector.loki.enable is true')} />
48	              ) : undefined
49	            }
50	            title={<TabTitleText>{t('Traffic flows')}</TabTitleText>}
51	          />
52	          <Tab
53	            className="topologyTabButton"
54	            eventKey={'topology'}
55	            title={<TabTitleText>{t('Topology')}</TabTitleText>}
56	          />
57	        </Tabs>
58	      </FlexItem>
59	      {props.selectedViewId === 'table' && (
60	        <FlexItem className={'bottom-border'}>
61	          <Button
62	            data-test="show-histogram-button"
63	            id="show-histogram-button"
64	            variant="link"
65	            className="overflow-button"
66	            onClick={() => {
67	              props.setShowViewOptions(false);
68	              props.setShowHistogram(!props.showHistogram);
69	              props.setHistogramRange(undefined);
70	            }}
71	          >
72	            {props.showHistogram ? t('Hide histogram') : t('Show histogram')}
73	          </Button>
74	        </FlexItem>
75	      )}
76	      <FlexItem className={'bottom-border'}>
77	        <Button
78	          data-test="show-view-options-button"
79	          id="show-view-options-button"
80	          variant="link"
81	          className="overflow-button"
82	          onClick={() => {
83	            props.setShowViewOptions(!props.isShowViewOptions);
84	            props.setShowHistogram(false);
85	            props.setHistogramRange(undefined);
86	          }}
87	        >
88	          {props.isShowViewOptions ? t('Hide advanced options') : t('Show advanced options')}
89	        </Button>
90	      </FlexItem>
91	    </Flex>
92	  );
93	};
94	
95	export default TabsContainer;

